define('taoQtiTest/controller/creator/views/actions',['jquery', 'taoQtiTest/controller/creator/views/property', 'taoQtiTest/controller/creator/helpers/subsection'], function ($, propertyView, subsectionsHelper) {
  'use strict';

  var disabledClass = 'disabled';
  var activeClass = 'active';
  var btnOnClass = 'tlb-button-on';
  function properties($container, template, model, cb) {
    var propView = null;
    $container.find('.property-toggler').on('click', function (e) {
      e.preventDefault();
      var $elt = $(this);
      if (!$(this).hasClass(disabledClass)) {
        $elt.blur();
        if (propView === null) {
          $container.addClass(activeClass);
          $elt.addClass(btnOnClass);
          propView = propertyView(template, model);
          propView.open();
          propView.onOpen(function () {
            $container.addClass(activeClass);
            $elt.addClass(btnOnClass);
          });
          propView.onClose(function () {
            $container.removeClass(activeClass);
            $elt.removeClass(btnOnClass);
          });
          if (typeof cb === 'function') {
            cb(propView);
          }
        } else {
          propView.toggle();
        }
      }
    });
  }
  function move($actionContainer, containerClass, elementClass) {
    var $element = $actionContainer.closest(".".concat(elementClass));
    var $container = $element.closest(".".concat(containerClass));
    $('.move-up', $actionContainer).click(function (e) {
      var $elements, index;
      e.preventDefault();
      if ($element.is(':animated') && $element.hasClass('disabled')) {
        return false;
      }
      $elements = $container.children(".".concat(elementClass));
      index = $elements.index($element);
      if (index > 0) {
        $element.fadeOut(200, () => {
          $element.insertBefore($container.children(".".concat(elementClass, ":eq(").concat(index - 1, ")"))).fadeIn(400, () => $container.trigger('change'));
        });
      }
    });
    $('.move-down', $actionContainer).click(function (e) {
      var $elements, index;
      e.preventDefault();
      if ($element.is(':animated') && $element.hasClass('disabled')) {
        return false;
      }
      $elements = $container.children(".".concat(elementClass));
      index = $elements.index($element);
      if (index < $elements.length - 1 && $elements.length > 1) {
        $element.fadeOut(200, () => {
          $element.insertAfter($container.children(".".concat(elementClass, ":eq(").concat(index + 1, ")"))).fadeIn(400, () => $container.trigger('change'));
        });
      }
    });
  }
  function movable($container, elementClass, actionContainerElt) {
    $container.each(function () {
      var $elt = $(this);
      var $actionContainer = $elt.children(actionContainerElt);
      var index = $container.index($elt);
      var $moveUp = $('.move-up', $actionContainer);
      var $moveDown = $('.move-down', $actionContainer);
      if ($container.length === 1) {
        $moveUp.addClass(disabledClass);
        $moveDown.addClass(disabledClass);
      } else if (index === 0) {
        $moveUp.addClass(disabledClass);
        $moveDown.removeClass(disabledClass);
      } else if (index >= $container.length - 1) {
        $moveDown.addClass(disabledClass);
        $moveUp.removeClass(disabledClass);
      } else {
        $moveUp.removeClass(disabledClass);
        $moveDown.removeClass(disabledClass);
      }
    });
  }
  function removable($container, actionContainerElt) {
    $container.each(function () {
      var $elt = $(this);
      var $actionContainer = $elt.children(actionContainerElt);
      var $delete = $('[data-delete]', $actionContainer);
      if ($container.length <= 1 && !$elt.hasClass('subsection')) {
        $delete.addClass(disabledClass);
      } else {
        $delete.removeClass(disabledClass);
      }
    });
  }
  function disable($container, actionContainerElt) {
    if ($container.length <= 2) {
      $container.children(actionContainerElt).find('[data-delete]').addClass(disabledClass);
    }
  }
  function enable($container, actionContainerElt) {
    $container.children(actionContainerElt).find('[data-delete],.move-up,.move-down').removeClass(disabledClass);
  }
  function displayItemWrapper($section) {
    var $elt = $('.itemrefs-wrapper:first', $section);
    var subsectionsCount = subsectionsHelper.getSubsections($section).length;
    if (subsectionsCount) {
      $elt.hide();
    } else {
      $elt.show();
    }
  }
  function updateDeleteSelector($actionContainer) {
    var $deleteButton = $actionContainer.find('.delete-subsection');
    if ($deleteButton.parents('.subsection').length > 1) {
      var deleteSelector = $deleteButton.data('delete');
      $deleteButton.attr('data-delete', "".concat(deleteSelector, " .subsection"));
    }
  }
  function displayCategoryPresets($authoringContainer) {
    var scope = arguments.length > 1 && arguments[1] !== undefined ? arguments[1] : 'section';
    var id = $authoringContainer.attr('id');
    var $propertiesView = $(".test-creator-props #".concat(scope, "-props-").concat(id));
    if (!$propertiesView.length) {
      return;
    }
    var $elt = $propertiesView.find('.category-presets');
    switch (scope) {
      case 'testpart':
        $elt.show();
        break;
      case 'section':
        var subsectionsCount = subsectionsHelper.getSubsections($authoringContainer).length;
        if (subsectionsCount) {
          $elt.hide();
          $propertiesView.trigger('set-default-categories');
        } else {
          $elt.show();
        }
        break;
    }
  }
  function updateTitleIndex($list) {
    $list.each(function () {
      var $elt = $(this);
      var $indexSpan = $('.title-index', $elt.children('h2'));
      if ($elt.hasClass('section')) {
        var $parent = $elt.parents('.sections');
        var index = $('.section', $parent).index($elt);
        $indexSpan.text("".concat(index + 1, "."));
      } else {
        $indexSpan.text(subsectionsHelper.getSubsectionTitleIndex($elt));
      }
    });
  }
  return {
    properties,
    move,
    removable,
    movable,
    disable,
    enable,
    displayItemWrapper,
    updateDeleteSelector,
    displayCategoryPresets,
    updateTitleIndex
  };
});
