define('taoQtiTest/controller/creator/helpers/sectionBlueprints',['lodash', 'i18n', 'core/errorHandler'], function (_, __, errorHandler) {
  'use strict';

  var _ns = '.sectionBlueprint';
  function setBlueprint(model, blueprint) {
    model.blueprint = blueprint;
  }
  function getBlueprint(getUrl, model) {
    return $.ajax({
      url: getUrl,
      type: 'GET',
      data: {
        section: model.identifier
      },
      dataType: 'json'
    }).fail(function () {
      errorHandler.throw(_ns, 'invalid tool config format');
    });
  }
  return {
    setBlueprint: setBlueprint,
    getBlueprint: getBlueprint
  };
});
