define('taoQtiTest/controller/creator/helpers/categorySelector',['jquery', 'lodash', 'i18n', 'core/eventifier', 'ui/dialog/confirm', 'ui/tooltip', 'taoQtiTest/controller/creator/templates/index', 'taoQtiTest/controller/creator/helpers/featureVisibility', 'select2'], function ($, _, __, eventifier, confirmDialog, tooltip, templates, featureVisibility) {
  'use strict';

  var allPresets = [];
  var allQtiCategoriesPresets = [];
  var categoryToPreset = new Map();
  function isValidCategory(category) {
    var genericCategoryRegex = /^[a-zA-Z_][a-zA-Z0-9_-]*$/;
    var attachmentCategoryRegex = /^x-tao-attachment-([0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12})$/i;
    if (category.startsWith('x-tao-attachment-')) {
      return attachmentCategoryRegex.test(category);
    }
    return genericCategoryRegex.test(category);
  }
  function categorySelectorFactory($container) {
    var $presetsContainer = $container.find('.category-presets');
    var $customCategoriesSelect = $container.find('[name=category-custom]');
    var categorySelector = {
      updateCategories() {
        var presetSelected = $container.find('.category-preset input:checked').toArray().map(categoryEl => categoryEl.value),
          presetIndeterminate = $container.find('.category-preset input:indeterminate').toArray().map(categoryEl => categoryEl.value),
          customSelected = $customCategoriesSelect.siblings('.select2-container').find('.select2-search-choice').not('.partial').toArray().map(categoryEl => categoryEl.textContent && categoryEl.textContent.trim()),
          customIndeterminate = $customCategoriesSelect.siblings('.select2-container').find('.select2-search-choice.partial').toArray().map(categoryEl => categoryEl.textContent && categoryEl.textContent.trim());
        var selectedCategories = presetSelected.concat(customSelected);
        var indeterminatedCategories = presetIndeterminate.concat(customIndeterminate);
        this.trigger('category-change', selectedCategories, indeterminatedCategories);
      },
      createForm(currentCategories, level) {
        var presetsTpl = templates.properties.categorypresets;
        var customCategories = _.difference(currentCategories, allQtiCategoriesPresets);
        var filteredPresets = featureVisibility.filterVisiblePresets(allPresets, level);
        $presetsContainer.append(presetsTpl({
          presetGroups: filteredPresets
        }));
        $presetsContainer.on('click', e => {
          var $preset = $(e.target).closest('.category-preset');
          if ($preset.length) {
            var $checkbox = $preset.find('input');
            $checkbox.prop('indeterminate', false);
            _.defer(() => this.updateCategories());
          }
        });
        $customCategoriesSelect.select2({
          width: '100%',
          containerCssClass: 'custom-categories',
          tags: customCategories,
          multiple: true,
          tokenSeparators: [',', ' ', ';'],
          createSearchChoice: category => isValidCategory(category) ? {
            id: category,
            text: category
          } : null,
          formatNoMatches: () => __('Category name not allowed'),
          maximumInputLength: 60
        }).on('change', () => this.updateCategories());
        $container.find('.custom-categories').on('click', '.partial', e => {
          var $choice = $(e.target).closest('.select2-search-choice');
          var tag = $choice.text().trim();
          confirmDialog(__('Do you want to apply the category "%s" to all included items?', tag), () => {
            $choice.removeClass('partial');
            this.updateCategories();
          });
        });
        tooltip.lookup($container);
      },
      updateFormState(selected, indeterminate) {
        indeterminate = indeterminate || [];
        var customCategories = _.difference(selected.concat(indeterminate), allQtiCategoriesPresets);
        var $presetsCheckboxes = $container.find('.category-preset input');
        $presetsCheckboxes.each((idx, input) => {
          var qtiCategory = input.value;
          if (!categoryToPreset.has(qtiCategory)) {
            input.indeterminate = indeterminate.includes(qtiCategory);
            input.checked = selected.includes(qtiCategory);
            return;
          }
          var preset = categoryToPreset.get(qtiCategory);
          var hasCategory = category => preset.categories.includes(category);
          input.indeterminate = indeterminate.some(hasCategory);
          input.checked = selected.some(hasCategory);
        });
        $customCategoriesSelect.select2('val', customCategories);
        $customCategoriesSelect.siblings('.select2-container').find('.select2-search-choice').each((idx, li) => {
          var $li = $(li);
          var content = $li.find('div').text();
          if (indeterminate.indexOf(content) !== -1) {
            $li.addClass('partial');
          }
        });
      }
    };
    eventifier(categorySelector);
    return categorySelector;
  }
  categorySelectorFactory.setPresets = function setPresets(presets) {
    if (Array.isArray(presets)) {
      allPresets = Array.from(presets);
      categoryToPreset = new Map();
      allQtiCategoriesPresets = allPresets.reduce((allCategories, group) => {
        return group.presets.reduce((all, preset) => {
          var categories = [preset.qtiCategory].concat(preset.altCategories || []);
          categories.forEach(category => categoryToPreset.set(category, preset));
          preset.categories = categories;
          return all.concat(categories);
        }, allCategories);
      }, []);
    }
  };
  categorySelectorFactory._isValidCategory = isValidCategory;
  return categorySelectorFactory;
});
